import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Redirect } from 'react-router-dom';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://authorization-server.com/auth';
const tokenEndpoint = 'https://authorization-server.com/token';

const App = () => {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('accessToken'));

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      fetchAccessToken(code);
    }
  }, []);

  const fetchAccessToken = async (code) => {
    const response = await fetch(tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code,
        redirect_uri: redirectUri,
        client_id: clientId,
      }),
    });
    const data = await response.json();
    if (data.access_token) {
      localStorage.setItem('accessToken', data.access_token);
      setAccessToken(data.access_token);
    }
  };

  const handleLogin = () => {
    window.location.href = `${authEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}`;
  };

  return (
    <Router>
      <Route path="/" exact>
        {accessToken ? <Redirect to="/dashboard" /> : <button onClick={handleLogin}>Login</button>}
      </Route>
      <Route path="/dashboard">
        {accessToken ? <Dashboard accessToken={accessToken} /> : <Redirect to="/" />}
      </Route>
    </Router>
  );
};

const Dashboard = ({ accessToken }) => {
  return <div>Welcome to the Dashboard! Your access token is: {accessToken}</div>;
};

export default App;